-- Simple index on a frequently queried column
CREATE INDEX IX_Orders_CustomerId ON Orders(CustomerId);

-- Composite index — good for queries filtering both columns
CREATE INDEX IX_Orders_Status_Date ON Orders(Status, OrderDate DESC);

-- Unique index — enforces uniqueness AND provides index benefit
CREATE UNIQUE INDEX UX_Users_Email ON Users(Email);

-- An index DOES help this:
SELECT * FROM Orders WHERE CustomerId = 42;
-- An index does NOT help this (leading wildcard):
SELECT * FROM Users WHERE Email LIKE '%@gmail.com'; -- full scan

-- NULL comparisons (all return UNKNOWN, not TRUE/FALSE)
SELECT * FROM Users WHERE Phone = NULL;   -- ❌ returns 0 rows

-- ✅ Correct way to check for NULL
SELECT * FROM Users WHERE Phone IS NULL;

-- COALESCE — returns first non-NULL value
SELECT Name,
    COALESCE(Phone, MobilePhone, 'No phone') AS ContactNumber
FROM Users;

-- NULLIF — returns NULL if two values are equal (avoid divide by zero)
SELECT Revenue / NULLIF(OrderCount, 0) AS AvgRevenue FROM Summary;

-- SQL Server: check execution plan and I/O stats
SET STATISTICS IO ON;

-- ❌ Function on indexed column breaks the index
SELECT * FROM Orders WHERE YEAR(OrderDate) = 2024;
-- ✅ Rewrite to use index on OrderDate
SELECT * FROM Orders
WHERE OrderDate >= '2024-01-01' AND OrderDate < '2025-01-01';

-- ❌ N+1 problem — 1 query for orders + 1 per order for customer
-- SELECT * FROM Orders; then SELECT * FROM Customers WHERE Id = @id

-- ✅ Use JOIN instead
SELECT o.Id, o.Amount, c.Name
FROM Orders o
INNER JOIN Customers c ON o.CustomerId = c.Id;

-- Bank transfer transaction
BEGIN TRANSACTION;

BEGIN TRY
    UPDATE Accounts
    SET Balance = Balance - 500
    WHERE AccountId = 1 AND Balance >= 500;

    IF @@ROWCOUNT = 0
        THROW 50001, 'Insufficient funds', 1;

    UPDATE Accounts
    SET Balance = Balance + 500
    WHERE AccountId = 2;

    COMMIT TRANSACTION;
END TRY
BEGIN CATCH
    ROLLBACK TRANSACTION;
    SELECT ERROR_MESSAGE() AS ErrorMessage;
END CATCH;

-- VIEW — simplified named query
CREATE VIEW vw_ActiveCustomerOrders AS
SELECT c.Name, COUNT(o.Id) AS OrderCount, SUM(o.Amount) AS TotalSpend
FROM Customers c
INNER JOIN Orders o ON c.Id = o.CustomerId
WHERE c.IsActive = 1
GROUP BY c.Id, c.Name;

-- STORED PROCEDURE — parameterized, can do DML
CREATE PROCEDURE usp_ProcessRefund
    @OrderId INT, @Reason NVARCHAR(500)
AS BEGIN
    BEGIN TRANSACTION;
    UPDATE Orders SET Status = 'Refunded' WHERE Id = @OrderId;
    INSERT INTO RefundLog (OrderId, Reason) VALUES (@OrderId, @Reason);
    COMMIT;
END;

-- TABLE-VALUED FUNCTION
CREATE FUNCTION fn_GetOrdersByDateRange(@Start DATE, @End DATE)
RETURNS TABLE AS
RETURN SELECT * FROM Orders WHERE OrderDate BETWEEN @Start AND @End;
